  const folder = await googleJson('https://www.googleapis.com/drive/v3/files?supportsAllDrives=true', token, 'POST', {
    name,
    mimeType: 'application/vnd.google-apps.folder',
    parents: [parentId],
  });
  return {
    id: folder.id,
    url: `https://drive.google.com/drive/folders/${folder.id}`,
  };
}

